];

return $input.all().map((itemWrapper) => {
  const item = itemWrapper.json;
  const contact = item.contact_data || {};
  const text = [
    contact.source_url || '',
    contact.organization || '',
    item.metadata?.title || '',
    item.metadata?.snippet || '',
    item.snippet || ''
  ].join(' ').toLowerCase();

  let inferred = null;
  for (const rule of regionRules) {
    if (rule.keys.some(key => text.includes(key))) {
      inferred = rule.region;
      break;
    }
  }

  if (inferred) {
    contact.region = inferred;
    item.region = inferred;
  }

  item.contact_data = contact;
  return { json: item };
});

