  {{$json.contact_data.source_type ? `'${$json.contact_data.source_type.replace(/'/g, "''")}'` : 'NULL'}},
  NULL,
  1,
  {{ Number($json.contact_data.validation_score || 1) }}
)
ON DUPLICATE KEY UPDATE
  id = LAST_INSERT_ID(id),
  updated_at = CURRENT_TIMESTAMP;

SET @cid = LAST_INSERT_ID();

INSERT INTO search_results (search_id, contact_id, relevance_score)
SELECT
  @sid,
  @cid,
  COALESCE((SELECT validation_score FROM contacts WHERE id = @cid), 1)
WHERE @sid > 0
ON DUPLICATE KEY UPDATE
  relevance_score = VALUES(relevance_score);

SELECT @sid AS search_id, @cid AS contact_id;

