const webhookData = $("Webhook").first().json;
const inserted = $("Insert Valid Contacts").all().length;

// En Webhook de n8n normalmente viene en body
const rawSearchId = webhookData?.body?.search_id ?? webhookData?.search_id;

const searchId = Number(rawSearchId);
if (!Number.isInteger(searchId) || searchId <= 0) {
  throw new Error(`search_id inválido. Valor recibido: ${JSON.stringify(rawSearchId)}`);
}

return [{
